template = """
        <div class="deep-dive" style="margin-top: 30px; padding: 25px; border: 2px dashed #9c27b0; border-radius: 12px; color: #333; background: #fffaf0;">
            <h3 style="color: #6a1b9a; margin-bottom: 15px;">🔍 {topic}</h3>
            <p><em>{author}</em></p>
            <h4 style="color: #8e24aa; margin-top: 20px;">{deep_dive_title}</h4>
            {content}
            <hr style="border: 1px solid #e1bee7; margin: 20px 0;">
            {faq}
        </div>
"""

for filename, data in files_data.items():
    filepath = os.path.join("/Users/calro/Desktop/jlpt_thai_app", filename)
    if os.path.exists(filepath):
        with open(filepath, "r", encoding="utf-8") as f:
            html = f.read()
        
        new_content = template.format(
            topic=data["topic"],
            author=data["author"],
            deep_dive_title=data["deep_dive_title"],
            content=data["content"],
            faq=data["faq"]
        )
        
        if '<div class="original-content"' in html:
            html = re.sub(r'<div class="original-content".*?(?=<footer>)', new_content + '\n\n', html, flags=re.DOTALL)
        else:
            html = html.replace("<footer>", new_content + "\n<footer>")
            
        with open(filepath, "w", encoding="utf-8") as f:
            f.write(html)
        print(f"Updated {filename}")
    else:
        print(f"File {filename} not found.")
